step.parameter:
acc_string=$(awk -F, '{print $1}' .data/scatac.norm.csv | awk -v prefix="$prefix" -v suffix="$suffix" '{printf "%s%s%s ", prefix, $1, suffix}' | sed 's/ $//')
cluster_names=$(awk -F, '{print $1}' .data/scatac.norm.csv | paste -sd ' ' -)
folder="./log_r1/{{JobName}}-r1/";
expected_model_file=$(find "$folder" -maxdepth 2 -type f -name "*.ckpt" | sort -r | head -n 1);
export PYTHONPATH={{Workspace}}/DeepDETAILS/src:$PYTHONPATH
python DeepDETAILS/src/deepdetails/cli.py export-gw-pred -m $expected_model_file --genome-fa {{HG38_PRIMARY_FA}} --regions-file {{GenomeWide4T1Regions}} --bulk-pl ./data/out.pl.bw --bulk-mn ./data/out.mn.bw --accessibility ${acc_string} --sc-norm ./data/scatac.norm.csv --ref-labels ${cluster_names} --study-name {{JobName}}-r1 {{FlexParExporting}}

